+#[test]
+fn test_version_parsing_with_prerelease() {
+    let versions = vec![
+        "1.0.0-alpha",
+        "1.0.0-alpha.1",
+        "1.0.0-beta",
+        "1.0.0-beta.2",
+        "1.0.0-rc.1",
+        "2.0.0-alpha+build.123",
+    ];
+
+    for version_str in versions {
+        let parsed = semver::Version::parse(version_str);
+        assert!(parsed.is_ok(), "Failed to parse: {version_str}");
+    }
+}
